const items = $input.first().json.items;
const overdue = items.filter(i => new Date(i.dueDate) < new Date());
const today = items.filter(i => new Date(i.dueDate).toDateString() === new Date().toDateString());
const upcoming = items.filter(i => new Date(i.dueDate) > new Date());
return [
  { category: 'overdue', count: overdue.length, items: overdue },
  { category: 'today', count: today.length, items: today },
  { category: 'upcoming', count: upcoming.length, items: upcoming }
];

const data = $input.all();
const overdue = data.find(d => d.json.category === 'overdue');
const today = data.find(d => d.json.category === 'today');

let message = '📋 *Checklist Alert — Obras*
';
if (overdue.json.count > 0) {
  message += `
🔴 *${overdue.json.count} checklists VENCIDOS:*`;
  overdue.json.items.forEach(i => message += `
  • Obra #${i.obraId}: ${i.title} (vencido em ${i.dueDate})`);
}
if (today.json.count > 0) {
  message += `

🟡 *${today.json.count} checklists para HOJE:*`;
  today.json.items.forEach(i => message += `
  • Obra #${i.obraId}: ${i.title}`);
}
if (overdue.json.count === 0 && today.json.count === 0) {
  message += '
✅ Nenhum checklist pendente crítico.';
}
return { text: message };
